mapper.select:
SELECT l.id, l.asset, el.name AS priority_name, l.capacity, l.`status`, l.alert_acknowledged, l.disable_notification, l.resolved, IF(l.`status` = 1, 'Opened', 'Closed') AS status_name, DATE_FORMAT(CONVERT_TZ( d.last_updated,'UTC', t.value), '%c/%e/%Y %h:%i %p') AS last_updated, el.`name` AS `level`, e.message, e.error_code, d.devicename, d.datatablename, d.view_tablename, d.job_tablename, AS site_name, s.id AS id_site, SHA1(s.id) AS hash_id, d.id as id_device, h.is_hiding, i.icon AS icon_alert, el.id AS id_error_level, DATE_FORMAT( CONVERT_TZ( l.start_date, t.`offset`, #{offset_timezone} ), #{format_sql_long} ) AS start, DATE_FORMAT( CONVERT_TZ( l.start_date,'+00:00', t.`offset`) , '%m/%d/%Y %H:%i %p') AS start_date, DATE_FORMAT(CONVERT_TZ( l.end_date,'+00:00', t.`offset`), '%m/%d/%Y %H:%i %p') AS end_date,
CASE WHEN CONVERT_TZ( l.start_date, '+00:00', t.`offset` ) < DATE_ADD( DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i'), INTERVAL -1 DAY ) THEN TIMESTAMPDIFF( DAY, CONVERT_TZ( l.start_date, '+00:00', t.`offset` ), DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i') ) WHEN CONVERT_TZ( l.start_date, '+00:00', t.`offset` ) < DATE_ADD( DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i'), INTERVAL -1 HOUR ) THEN TIMESTAMPDIFF( HOUR, CONVERT_TZ( l.start_date, '+00:00', t.`offset` ), DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i') ) WHEN CONVERT_TZ( l.start_date, '+00:00', t.`offset` ) < DATE_ADD( DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i'), INTERVAL -1 MINUTE ) THEN TIMESTAMPDIFF( MINUTE, CONVERT_TZ( l.start_date, '+00:00', t.`offset` ), DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i') ) ELSE 0 END AS times_ago,
CASE WHEN CONVERT_TZ( l.start_date, '+00:00', t.`offset` ) < DATE_ADD( DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i'), INTERVAL - 1 DAY ) THEN 'day' WHEN CONVERT_TZ( l.start_date, '+00:00', t.`offset` ) < DATE_ADD( DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i'), INTERVAL - 1 HOUR ) THEN 'hour' WHEN CONVERT_TZ( l.start_date, '+00:00', t.`offset` ) < DATE_ADD( DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d %H:%i'), INTERVAL - 1 MINUTE ) THEN 'minute' ELSE 'now' END AS times_ago_unit,
FROM `alert` l LEFT JOIN error e ON e.id = l.id_error LEFT JOIN error_level el ON el.id = e.id_error_level LEFT JOIN icon i ON i.id = el.id_icon LEFT JOIN device d ON d.id = l.id_device LEFT JOIN device_group dg ON dg.id = d.id_device_group LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN ( SELECT id_site, MAX(is_hiding) AS is_hiding FROM site_employee_map GROUP BY id_site ) h ON h.id_site = s.id WHERE e.`status` = 1 AND e.is_delete = 0 AND l.is_delete = 0 AND l.status = 1 AND (CONVERT_TZ(NOW(), '+00:00', t.offset) < s.expiration OR s.expiration IS NULL)
AND s.id IN (
#{item.id}
)
AND el.id != 14
GROUP BY l.id
ORDER BY
l.id ${order_by}
e.error_code ${order_by}
s.`name` ${order_by}
d.`devicename` ${order_by}
key_indicator ${order_by}
l.start_date ${order_by}
e.message ${order_by}
l.start_date DESC

SELECT s.id AS id_site, AS site_name, SHA1(s.id) AS hash_id, s.dc_capacity, ROUND(IFNULL(vir.activePower, IFNULL(meter.activePower, inv.activePower)), 1) AS power_today, ROUND(IFNULL(vir.expected_power_virtual, IFNULL(wea.expected_power, ep.expected)), 1) AS expected, ROUND(IFNULL(vir.activePower, IFNULL(meter.activePower, inv.activePower)) / IFNULL(vir.expected_power_virtual, IFNULL(wea.expected_power, ep.expected)) * 100, 1) AS a_e, h.is_hiding
FROM `site` s LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN () vir ON vir.id_site = s.id LEFT JOIN () inv ON inv.id_site = s.id LEFT JOIN () meter ON meter.id_site = s.id LEFT JOIN () wea ON wea.id_site = s.id
LEFT JOIN ( SELECT ee.id_site, ee.`year`, CASE WHEN DATE_FORMAT('2022-08-10', '%b') = 'Jan' THEN ROUND((((ee.jan * 1000)/31) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Feb' THEN ROUND((((ee.feb * 1000)/28) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Mar' THEN ROUND((((ee.mar * 1000)/31) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Apr' THEN ROUND((((ee.apr * 1000)/30) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'May' THEN ROUND((((ee.may * 1000)/31) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Jun' THEN ROUND((((ee.jun * 1000)/30) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Jul' THEN ROUND((((ee.jul * 1000)/31) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Aug' THEN ROUND((((ee.aug * 1000)/31) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Sep' THEN ROUND((((ee.sep * 1000)/30) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Oct' THEN ROUND((((ee.oct * 1000)/31) / (8*0.75))/1000,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Nov' THEN ROUND((((ee.nov * 1000)/30) / (8*0.75))/1000 ,1) WHEN DATE_FORMAT('2022-08-10', '%b') = 'Dec' THEN ROUND((((ee.`dec` * 1000)/31) / (8*0.75))/1000,1) ELSE 0 END AS expected
FROM energy_expectations ee LEFT JOIN site s ON s.id = ee.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone WHERE ee.`year` = DATE_FORMAT( CONVERT_TZ( NOW(), '+00:00', t.`offset` ) , '%Y-%m-%d') AND (CONVERT_TZ(NOW(), '+00:00', t.offset) < s.expiration OR s.expiration IS NULL) )ep ON ep.id_site = s.id
LEFT JOIN ( SELECT id_site, MAX(is_hiding) AS is_hiding FROM site_employee_map GROUP BY id_site ) h ON h.id_site = s.id
WHERE s.`status` = 1 AND s.is_delete = 0 AND (CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', t.value) < s.expiration OR s.expiration IS NULL)
AND s.id IN (
#{item.id}
)
GROUP BY s.id
ORDER BY
s.name ${order_by}
power_today ${order_by}
expected ${order_by}
a_e ${order_by}
s.id DESC

SELECT (
) AS lowPriority, (
) AS highPriority, (
) AS totalError,
( SELECT IFNULL(ROUND(SUM(IFNULL(v.activePower, IFNULL(m.activePower, ivt.activePower))), 2), 0) AS generationNow FROM site s LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN () v ON v.id_site = s.id LEFT JOIN () ivt ON ivt.id_site = s.id LEFT JOIN () m ON m.id_site = s.id WHERE s.`status` = 1 AND s.`is_delete` = 0 AND (CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', t.value) < s.expiration OR s.expiration IS NULL)
AND s.id IN (
#{item.id}
)
) AS generationNow,
( SELECT COUNT(s.id) AS totalSite FROM site s WHERE s.`status` = 1
AND s.id IN (
#{item.id}
)
) AS totalSite,
( SELECT SUM(s.dc_capacity) AS ratedDCCapacity FROM site s WHERE s.`status` = 1
AND s.id IN (
#{item.id}
)
) AS ratedDCCapacity

SELECT SUM(actual) AS actual FROM (
SELECT (SELECT nvmActiveEnergy FROM ${item.datatablename} WHERE time = maxTime AND id_device = #{item.id}) - nvmActiveEnergy AS actual FROM ${item.datatablename} dv JOIN ( SELECT MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime FROM ${item.datatablename} dv WHERE dv.id_device = #{item.id} AND dv.nvmActiveEnergy IS NOT NULL AND dv.time BETWEEN #{start_time} AND #{end_time} ) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) t

SELECT SUM(expected_energy) as expected FROM ( SELECT ROUND(IF( AVG(irradiance) IS NULL, NULL, AVG(
) * #{duration} ), 1) AS expected_energy FROM ( SELECT id AS id_site, AVG(temperature) AS temperature, AVG(panelTemperature) AS panelTemperature, AVG(irradiance) AS irradiance FROM (
SELECT s.id, AVG(dv.nvm_temperature) AS temperature, AVG(dv.nvm_panel_temperature) AS panelTemperature, NULL AS irradiance FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE s.id = #{item.id_site} AND s.`status` = 1 AND d.`status` = 1 AND d.id = #{item.id} AND dv.time BETWEEN #{start_time} AND #{end_time}
UNION ALL
SELECT s.id, NULL AS temperature, NULL AS panelTemperature, AVG(dv.nvm_irradiance) AS irradiance FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE s.id = #{item.id_site} AND s.`status` = 1 AND d.`status` = 1 AND d.id = #{item.id} AND dv.time BETWEEN #{start_time} AND #{end_time}
) t ) t JOIN site s ON s.id = t.id_site ) t

SELECT
AVG(






) * #{duration}
FROM
    ${datatablename} dv
LEFT JOIN device d ON d.id = dv.id_device
LEFT JOIN site s ON s.id = d.id_site
WHERE
    dv.time BETWEEN #{start_time} AND #{end_time}

SELECT name, lat, lng FROM site WHERE status = 1 AND is_delete = 0
AND id IN
#{id}

WITH RECURSIVE hours AS ( SELECT CAST(#{start_time} AS DATETIME) AS category_time UNION ALL SELECT DATE_ADD(category_time, INTERVAL 1 HOUR) FROM hours WHERE DATE_ADD(category_time, INTERVAL 1 HOUR) <= #{end_time} ),
device_power_data AS ( SELECT DATE_FORMAT(dv.time, '%Y-%m-%d %H:00:00') AS category_time, AVG(
) AS expect_power FROM ${datatablename} dv LEFT JOIN device d ON d.id = dv.id_device LEFT JOIN site s ON s.id = d.id_site WHERE dv.id_device = #{id} AND dv.time BETWEEN #{start_time} AND #{end_time} GROUP BY DATE_FORMAT(dv.time, '%Y-%m-%d %H:00:00') ), summary_data AS ( SELECT category_time, SUM(expect_power) AS expect_power FROM device_power_data GROUP BY category_time ) SELECT DATE_FORMAT(CONVERT_TZ(h.category_time, 'UTC', #{time_zone_value}), '%Y-%m-%d %H:00:00') AS category_time, COALESCE(s.expect_power, 0) AS expect_power FROM hours h LEFT JOIN summary_data s ON s.category_time = DATE_FORMAT(h.category_time, '%Y-%m-%d %H:00:00') ORDER BY h.category_time

WITH RECURSIVE hours AS ( SELECT CAST(#{start_time} AS DATETIME) AS category_time UNION ALL SELECT DATE_ADD(category_time, INTERVAL 1 HOUR) FROM hours WHERE DATE_ADD(category_time, INTERVAL 1 HOUR) <= #{end_time} ), device_actual_data AS (
SELECT DATE_FORMAT(dv.time, '%Y-%m-%d %H:00:00') AS category_time, AVG(dv.nvmActivePower) AS actual_power FROM ${item.datatablename} dv WHERE dv.id_device = #{item.id} AND dv.time BETWEEN #{start_time} AND #{end_time} GROUP BY DATE_FORMAT(dv.time, '%Y-%m-%d %H:00:00')
), summary_data AS ( SELECT category_time, SUM(actual_power) AS actual_power FROM device_actual_data GROUP BY category_time ) SELECT DATE_FORMAT(CONVERT_TZ(h.category_time, 'UTC', #{time_zone_value}), '%Y-%m-%d %H:00:00') AS category_time, COALESCE(s.actual_power, 0) AS actual_power FROM hours h LEFT JOIN summary_data s ON s.category_time = DATE_FORMAT(h.category_time, '%Y-%m-%d %H:00:00') ORDER BY h.category_time

SELECT IFNULL(SUM(actual), 0) AS actual FROM (
SELECT (SELECT nvmActiveEnergy FROM ${item.datatablename} WHERE time = maxTime AND id_device = #{item.id}) - nvmActiveEnergy AS actual FROM ${item.datatablename} dv JOIN ( SELECT MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime FROM ${item.datatablename} dv WHERE dv.id_device = #{item.id} AND dv.nvmActiveEnergy IS NOT NULL AND dv.time BETWEEN CONVERT_TZ( DATE_FORMAT(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value}), '%Y-%m-%d 00:00:00'), #{item.timezone_value}, 'UTC' ) AND UTC_TIMESTAMP() ) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) t

SELECT d.id, d.devicename, d.datatablename, d.id_site, d.is_excluded_meter, d.reverse_poa, d.is_weather_to_calculate_expected, dt.id AS id_device_type, t.value AS timezone_value, d.id_device_group FROM device d JOIN device_type dt ON d.id_device_type = dt.id JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone
#{item}
AND d.`status` = 1 AND d.is_delete = 0 AND (CONVERT_TZ(NOW(), 'UTC', t.value) < s.expiration OR s.expiration IS NULL) AND (d.meter_type = 3 OR d.meter_type IS NULL)

SELECT d.id, d.devicename, d.datatablename, d.id_site, d.is_excluded_meter, d.reverse_poa, d.is_weather_to_calculate_expected, dt.id AS id_device_type, t.value AS timezone_value, d.id_device_group FROM device d JOIN device_type dt ON d.id_device_type = dt.id JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE
#{item}
AND d.`status` = 1 AND d.is_delete = 0 AND (CONVERT_TZ(NOW(), 'UTC', t.value) < s.expiration OR s.expiration IS NULL) AND d.id_device_type = 9

SELECT s.id, s.name AS site_name, c.name AS country, IFNULL(s.ac_capacity, 0) AS ac_capacity, IFNULL(s.dc_capacity, 0) AS dc_capacity, COUNT(a.id) AS total_count, SUM(el.id IN (32)) AS critical_count, SUM(el.id IN (12, 33)) AS warning_count FROM site s JOIN country c ON c.id = s.id_country JOIN device d ON d.id_site = s.id JOIN alert a ON a.id_device = d.id JOIN error e ON e.id = a.id_error JOIN error_level el ON el.id = e.id_error_level WHERE s.is_delete = 0 AND s.status = 1 AND a.is_delete = 0 AND a.end_date IS NULL
AND s.id = #{id}
GROUP BY s.id, s.name, c.name, s.ac_capacity, s.dc_capacity

SELECT s.id, SHA1(s.id) AS hash_id, AS `name`, IFNULL(s.ac_capacity, 0) as ac_capacity, IFNULL(s.dc_capacity, 0) as dc_capacity, IF(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL, ROUND(t.irradiance, 2), NULL) AS irradiance, IF(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL, ROUND(IFNULL(v.activePower, IFNULL(m.activePower, ivt.activePower)), 1), NULL) AS active_power, IF(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL, ROUND(IFNULL(v.expected_power_virtual, t.expected_power), 1), NULL) AS expected_power, tz.value as time_zone, IF(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL, ROUND(IFNULL(vd.actual, pd.actual), 1), NULL) AS actual_energy FROM site s LEFT JOIN company c ON c.id = s.id_company LEFT JOIN site_employee_map sem ON sem.id_site = s.id LEFT JOIN time_zone tz ON tz.id = s.id_time_zone LEFT JOIN () v ON v.id_site = s.id LEFT JOIN () t ON t.id_site = s.id LEFT JOIN () ivt ON ivt.id_site = s.id LEFT JOIN () m ON m.id_site = s.id LEFT JOIN () vd on vd.id_site = s.id LEFT JOIN () pd ON pd.id_site = s.id WHERE s.status = 1 and s.is_delete = 0 AND (CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', tz.value) < s.expiration OR s.expiration IS NULL)
AND s.id IN (
#{item}
)
GROUP BY s.id

choose.when:
SELECT SUM(actual) AS actual, id_site FROM (
SELECT #{item.id_site} AS id_site, dv.nvmActiveEnergy, (
) AS actual FROM ${item.datatablename} dv JOIN ( SELECT 1 AS currentTimeValid, 0 AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime, NULL AS lagMaxTime FROM ${item.datatablename} dv WHERE dv.id_device = #{item.id} AND dv.nvmActiveEnergy IS NOT NULL AND dv.time BETWEEN
CONVERT_TZ( DATE_SUB(DATE(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value})), INTERVAL WEEKDAY(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value})) + 7 DAY), #{item.timezone_value}, 'UTC' ) AND CONVERT_TZ( DATE_SUB(DATE(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value})), INTERVAL WEEKDAY(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value})) + 1 DAY), #{item.timezone_value}, 'UTC' )
CONVERT_TZ(DATE_FORMAT(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value}), '%Y-%m-01 00:00:00'), #{item.timezone_value}, 'UTC') AND UTC_TIMESTAMP()
CONVERT_TZ(DATE(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value})), #{item.timezone_value}, 'UTC') AND UTC_TIMESTAMP()
) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) t GROUP BY id_site

mapper.select:
SELECT CASE e.error_code WHEN 1000 THEN 'No Production' WHEN 1001 THEN 'Lost Communication' END AS error_type, s.NAME AS site_name, dg.group_name, dt.`name` AS device_type, d.devicename AS device_name, CASE e.error_code WHEN 1000 THEN '0.00 MW' WHEN 1001 THEN 'Offline' END AS device_status, CONCAT_WS( ' ', CASE WHEN FLOOR(TIMESTAMPDIFF(SECOND, a.start_date, UTC_TIMESTAMP()) / 86400) > 0 THEN CONCAT(FLOOR(TIMESTAMPDIFF(SECOND, a.start_date, UTC_TIMESTAMP()) / 86400), 'd') END, CASE WHEN FLOOR((TIMESTAMPDIFF(SECOND, a.start_date, UTC_TIMESTAMP()) % 86400) / 3600) > 0 THEN CONCAT(FLOOR((TIMESTAMPDIFF(SECOND, a.start_date, UTC_TIMESTAMP()) % 86400) / 3600), 'h') END, CASE WHEN FLOOR((TIMESTAMPDIFF(SECOND, a.start_date, UTC_TIMESTAMP()) % 3600) / 60) > 0 THEN CONCAT(FLOOR((TIMESTAMPDIFF(SECOND, a.start_date, UTC_TIMESTAMP()) % 3600) / 60), 'm') END ) AS duration, CASE e.error_code WHEN 1000 THEN 'critical' WHEN 1001 THEN 'warning' END AS severity FROM alert a JOIN error e ON e.id = a.id_error JOIN device d ON d.id = a.id_device JOIN device_group dg ON dg.id = d.id_device_group JOIN device_type dt ON dt.id = dg.id_device_type JOIN site s ON s.id = d.id_site WHERE
s.id IN (
#{item}
) AND
e.error_code IN (1000, 1001) AND a.end_date IS NULL AND a.is_delete = 0 AND a.STATUS = 1 AND s.is_delete = 0 AND d.is_delete = 0 ORDER BY e.error_code ASC, a.start_date DESC LIMIT #{limit}

SELECT s.id AS id_site, GROUP_CONCAT(d.datatablename) AS datatablenames FROM site s LEFT JOIN device d ON d.id_site = s.id WHERE d.id_device_group IN ( SELECT id_device_group FROM device_parameters WHERE slug = #{slug} ) AND d.is_excluded_meter = 0 AND d.is_delete = 0 AND s.status = 1 AND s.is_delete = 0 AND d.status = 1
AND s.id IN (
#{item.id}
)
GROUP BY s.id
